'use strict';

function expand(t) {
  return {
    ...t,
    services: t.s.map(([name,desc,price]) => ({name,desc,price:price||''})),
    faqs: t.f.map(([q,a]) => ({q,a})),
    blogs: t.b.map(([title,summary,tags]) => ({title,summary,tags})),
    reviews: t.r.map(([text,name,title]) => ({text,name,title})),
    process: t.p.map(([title,desc]) => ({title,desc})),
  };
}

