  f:[['有免費試聽嗎？','提供一堂免費試聽課程，可選擇任何語言與程度。透過線上預約即可報名。'],['班級人數多少？','小班制 6-10 人，確保每位學員有充足的練習機會。也提供一對一課程。'],['師資背景如何？','所有外師持有 TEFL/TESOL 等國際教學證書，中師具備語言教學相關碩博士學歷。'],['課程一期多久？','標準課程每期 12 週，每週上課 1-2 次，每次 90 分鐘。也有 4 週密集班可選。'],['可以補課嗎？','缺席可安排至同等級其他班級補課，或使用線上影片回放服務。'],['有線上課程嗎？','提供線上直播課程與實體課程並行，可自由選擇上課方式。'],['如何分級？','入學前進行免費程度測驗，根據聽說讀寫能力分級。'],['有檢定輔導嗎？','提供 IELTS、TOEFL、JLPT、TOPIK 等檢定衝刺班，含模擬考與解題。']],
  b:[['學語言的黃金年齡','科學研究顯示不同年齡段的語言學習優勢與策略。',['學習','科學']],['如何在家自學英語','搭配課程的自主學習方法與推薦資源清單。',['自學','英語']],['文化沉浸的重要性','為什麼學語言不只是背單字？文化理解的關鍵角色。',['文化','學習']],['學員專訪：從零到流利日語','聽學員 Amy 分享她的日語學習之路。',['學員','故事']],['多語人才在職場的優勢','語言能力如何為職涯加分？企業主的真實反饋。',['職涯','趨勢']],['AI 時代還需要學語言嗎？','AI 翻譯工具進步了，但人際溝通中的語言魅力無可取代。',['趨勢','科技']]],
  r:[['外師教學非常生動有趣，三個月就能用英語開會了！','張雅琳','行銷經理'],['日語課程很系統化，一年就通過了 N2 檢定。','李俊賢','大學生'],['兒童英語班讓女兒愛上了英文，每次都很期待上課。','陳怡君','家長'],['企業培訓課程很專業，講師特別針對我們的產業設計內容。','王建華','人資總監']],
  p:[['預約試聽','線上填寫表單，選擇想試聽的課程'],['程度測驗','進行免費語言程度評估'],['課程規劃','顧問根據目標與程度推薦課程'],['開始學習','正式開課，展開語言學習之旅']],
